from datetime import datetime
from typing import Optional

class ConsentAuditStore:
    """Append-only audit event store with temporal query support."""

    def append(self, event: ConsentAuditEvent) -> None:
        """Write an event. Raises on failure — do not swallow errors."""
        ...

    def query_at(
        self,
        user_id: str,
        feature_id: str,
        as_of: datetime,
    ) -> Optional[dict]:
        """Reconstruct the effective consent state at a given timestamp.
        Returns the last grant event before as_of, adjusted for any
        withdrawals, expirations, or overrides that occurred up to as_of.
        """
        events = self._events_for(
            user_id=user_id,
            feature_id=feature_id,
            up_to=as_of,
        )
        state = None
        for evt in sorted(events, key=lambda e: e.occurred_at):
            if evt.event_type == "consent_granted":
                state = {
                    "active": True,
                    "purposes": evt.purposes_granted,
                    "data_categories": evt.data_categories_allowed,
                    "session_only": evt.session_only,
                    "granted_at": evt.occurred_at,
                }
            elif evt.event_type in (
                "consent_withdrawn", "consent_expired", "admin_override_applied"
            ):
                if state:
                    state["active"] = False
        return state

    def export_user_history(
        self,
        user_id: str,
        from_dt: Optional[datetime] = None,
        to_dt: Optional[datetime] = None,
    ) -> list[ConsentAuditEvent]:
        """Return all consent events for a user, optionally date-bounded.
        Used for GDPR subject access requests.
        """
        return self._events_for(user_id=user_id, from_dt=from_dt, to_dt=to_dt)
